// AqlLexerInit initializes any static state used to implement AqlLexer. By default the
// static state used to implement the lexer is lazily initialized during the first call to
// NewAqlLexer(). You can call this function if you wish to initialize the static state ahead
// of time.
func AqlLexerInit() {
  staticData := &AqlLexerLexerStaticData
  staticData.once.Do(aqllexerLexerInit)
}

// NewAqlLexer produces a new lexer instance for the optional input antlr.CharStream.
func NewAqlLexer(input antlr.CharStream) *AqlLexer {
  AqlLexerInit()
	l := new(AqlLexer)
	l.BaseLexer = antlr.NewBaseLexer(input)
  staticData := &AqlLexerLexerStaticData
	l.Interpreter = antlr.NewLexerATNSimulator(l, staticData.atn, staticData.decisionToDFA, staticData.PredictionContextCache)
	l.channelNames = staticData.ChannelNames
	l.modeNames = staticData.ModeNames
	l.RuleNames = staticData.RuleNames
	l.LiteralNames = staticData.LiteralNames
	l.SymbolicNames = staticData.SymbolicNames
	l.GrammarFileName = "AqlLexer.g4"
	// TODO: l.EOF = antlr.TokenEOF

	return l
}

